1	export type Cell = [number, number];
2	
3	const key = (x: number, y: number): string => `${x},${y}`;
4	
5	const NEIGHBOR_OFFSETS: ReadonlyArray<[number, number]> = [
6	  [-1, -1], [-1, 0], [-1, 1],
7	  [0, -1],           [0, 1],
8	  [1, -1],  [1, 0],  [1, 1],
9	];
10	
11	const countLiveNeighbors = (x: number, y: number, liveSet: Set<string>): number => {
12	  let count = 0;
13	  for (const [dx, dy] of NEIGHBOR_OFFSETS) {
14	    if (liveSet.has(key(x + dx, y + dy))) count++;
15	  }
16	  return count;
17	};
18	
19	const survives = (isLive: boolean, neighbors: number): boolean =>
20	  (isLive && (neighbors === 2 || neighbors === 3)) || (!isLive && neighbors === 3);
21	
22	export const nextGeneration = (cells: Cell[]): Cell[] => {
23	  const liveSet = new Set<string>(cells.map(([x, y]) => key(x, y)));
24	
25	  const candidates = new Map<string, Cell>();
26	  for (const [x, y] of cells) {
27	    candidates.set(key(x, y), [x, y]);
28	    for (const [dx, dy] of NEIGHBOR_OFFSETS) {
29	      const nx = x + dx;
30	      const ny = y + dy;
31	      candidates.set(key(nx, ny), [nx, ny]);
32	    }
33	  }
34	
35	  const result: Cell[] = [];
36	  for (const [k, [x, y]] of candidates) {
37	    if (survives(liveSet.has(k), countLiveNeighbors(x, y, liveSet))) {
38	      result.push([x, y]);
39	    }
40	  }
41	
42	  return result;
43	};
