const collectCandidates = (cells: Cell[]): Map<string, Cell> => {
  const candidates = new Map<string, Cell>();
  const addCandidate = (x: number, y: number): void => {
    candidates.set(key(x, y), [x, y]);
  };
  for (const [x, y] of cells) {
    addCandidate(x, y);
    for (const [dx, dy] of NEIGHBOR_OFFSETS) {
      addCandidate(x + dx, y + dy);
    }
  }
  return candidates;
};

export const nextGeneration = (cells: Cell[]): Cell[] => {
  const liveSet = new Set<string>(cells.map(([x, y]) => key(x, y)));
  const candidates = collectCandidates(cells);

  const result: Cell[] = [];
  for (const [k, [x, y]] of candidates) {
    if (survives(liveSet.has(k), countLiveNeighbors(x, y, liveSet))) {
      result.push([x, y]);
    }
  }

  return result;
};
